CREATE TABLE tasks (id INTEGER PRIMARY KEY AUTOINCREMENT, slug TEXT NOT NULL UNIQUE, title TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'backlog', spec_markdown TEXT NOT NULL DEFAULT '', retry_count INTEGER NOT NULL DEFAULT 0, last_failure TEXT, repository_id TEXT, workflow_profile_id TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE runs (id INTEGER PRIMARY KEY AUTOINCREMENT, task_id INTEGER NOT NULL, role TEXT NOT NULL, agent_id TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'running', prompt TEXT, commit_sha TEXT, started_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, ended_at DATETIME, error TEXT, agent_version TEXT NOT NULL DEFAULT 'legacy', capabilities TEXT NOT NULL DEFAULT '{}', assignment_config TEXT NOT NULL DEFAULT '{}', supervisor_session_id TEXT, operation_id TEXT, verification_status TEXT, verification_output TEXT, agent_provenance TEXT NOT NULL DEFAULT '{}', failure TEXT, auth_recovery_resolved_at DATETIME, superseded_by_run_id INTEGER, FOREIGN KEY (task_id) REFERENCES tasks(id));
CREATE TABLE run_operations (id TEXT PRIMARY KEY, run_id INTEGER NOT NULL, operation TEXT NOT NULL, status TEXT NOT NULL, diagnostic TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, ended_at DATETIME, FOREIGN KEY (run_id) REFERENCES runs(id) ON DELETE CASCADE);
CREATE TABLE run_events (id INTEGER PRIMARY KEY AUTOINCREMENT, run_id INTEGER NOT NULL, seq INTEGER NOT NULL, type TEXT NOT NULL, payload TEXT NOT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (run_id) REFERENCES runs(id));
CREATE TABLE spec_messages (id INTEGER PRIMARY KEY AUTOINCREMENT, task_id INTEGER NOT NULL, role TEXT NOT NULL, content TEXT NOT NULL, prompt_status TEXT, failure TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (task_id) REFERENCES tasks(id));
CREATE TABLE chat_threads (id TEXT PRIMARY KEY, repository_id TEXT, repo_root TEXT NOT NULL, cwd TEXT NOT NULL, agent_id TEXT NOT NULL, agent_version TEXT NOT NULL DEFAULT 'legacy', title TEXT NOT NULL DEFAULT 'New session', status TEXT NOT NULL DEFAULT 'active', archived INTEGER NOT NULL DEFAULT 0, pinned INTEGER NOT NULL DEFAULT 0, task_slug TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, last_message_at DATETIME, scratch_markdown TEXT NOT NULL DEFAULT '', agent_provenance TEXT NOT NULL DEFAULT '{}', session_config_options TEXT NOT NULL DEFAULT '[]', session_modes TEXT, session_initialized INTEGER NOT NULL DEFAULT 0, failure TEXT, FOREIGN KEY (task_slug) REFERENCES tasks(slug));
CREATE TABLE chat_messages (id INTEGER PRIMARY KEY AUTOINCREMENT, thread_id TEXT NOT NULL, role TEXT NOT NULL, content TEXT NOT NULL, attachment_ids TEXT NOT NULL DEFAULT '[]', prompt_status TEXT, failure TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (thread_id) REFERENCES chat_threads(id) ON DELETE CASCADE);
CREATE TABLE chat_attachments (id TEXT PRIMARY KEY, thread_id TEXT NOT NULL, filename TEXT NOT NULL, mime_type TEXT NOT NULL, byte_size INTEGER NOT NULL, storage_name TEXT NOT NULL UNIQUE, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (thread_id) REFERENCES chat_threads(id) ON DELETE CASCADE);
CREATE TABLE acp_sessions (id TEXT PRIMARY KEY, owner_type TEXT NOT NULL, owner_id TEXT NOT NULL, agent_id TEXT NOT NULL, agent_version TEXT NOT NULL, acp_session_id TEXT, capabilities TEXT NOT NULL DEFAULT '{}', status TEXT NOT NULL DEFAULT 'starting', recovery_metadata TEXT NOT NULL DEFAULT '{}', diagnostic TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, started_at DATETIME, ended_at DATETIME, agent_provenance TEXT NOT NULL DEFAULT '{}', failure TEXT);
CREATE TABLE acp_prompts (id TEXT PRIMARY KEY, session_id TEXT NOT NULL, prompt TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'running', cancellation_requested_at DATETIME, diagnostic TEXT, started_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, ended_at DATETIME, content TEXT NOT NULL DEFAULT '{}', failure TEXT, message_id INTEGER, resubmission_of TEXT, FOREIGN KEY (session_id) REFERENCES acp_sessions(id) ON DELETE CASCADE);
CREATE TABLE acp_events (id INTEGER PRIMARY KEY AUTOINCREMENT, session_id TEXT NOT NULL, prompt_id TEXT, seq INTEGER NOT NULL, type TEXT NOT NULL, normalized TEXT NOT NULL, raw_payload TEXT NOT NULL, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (session_id) REFERENCES acp_sessions(id) ON DELETE CASCADE, FOREIGN KEY (prompt_id) REFERENCES acp_prompts(id) ON DELETE SET NULL);
CREATE TABLE permission_requests (id TEXT PRIMARY KEY, session_id TEXT NOT NULL, thread_id TEXT NOT NULL, request_id TEXT NOT NULL, tool TEXT NOT NULL, kind TEXT, raw_request TEXT NOT NULL, options TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'pending', selected_option_id TEXT, decision_action TEXT, diagnostic TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, resolved_at DATETIME, FOREIGN KEY (session_id) REFERENCES acp_sessions(id) ON DELETE CASCADE);
CREATE TABLE spec_author_sessions (id TEXT PRIMARY KEY, task_id INTEGER NOT NULL, repository_id TEXT NOT NULL, workflow_profile_id TEXT NOT NULL, assignment_id TEXT NOT NULL, agent_id TEXT NOT NULL, agent_version TEXT NOT NULL, capabilities TEXT NOT NULL DEFAULT '{}', assignment_config TEXT NOT NULL DEFAULT '{}', acp_session_id TEXT, supervisor_session_id TEXT, status TEXT NOT NULL DEFAULT 'active', agent_provenance TEXT NOT NULL DEFAULT '{}', failure TEXT, message_id INTEGER, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (task_id) REFERENCES tasks(id));
CREATE TABLE spec_author_operations (id INTEGER PRIMARY KEY AUTOINCREMENT, author_session_id TEXT NOT NULL, operation TEXT NOT NULL, status TEXT NOT NULL, diagnostic TEXT, failure TEXT, created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (author_session_id) REFERENCES spec_author_sessions(id) ON DELETE CASCADE);
CREATE INDEX idx_tasks_workflow_owner ON tasks(repository_id, workflow_profile_id);
